SELECT customer_key as "id", customer_key as "userId", first_name as "firstName", last_name as "lastName", email as "email", phone as "phone", customer_status as "stateId", customer_tier as "customerTier", segment as "segment", city as "city", state as "state", total_orders as "totalOrders", total_spent as "totalSpent", registered_date as "registeredDate", last_synced_at as "lastSyncedAt" FROM hm_query.dim_customer
AND customer_key = #{userId} AND email LIKE CONCAT('%', #{email}, '%') AND first_name LIKE CONCAT('%', #{firstName}, '%') AND last_name LIKE CONCAT('%', #{lastName}, '%') AND phone = #{phone} AND customer_status = #{stateId} AND customer_tier = #{customerTier} AND segment = #{segment} AND city LIKE CONCAT('%', #{city}, '%') AND state = #{state} AND (first_name LIKE CONCAT('%', #{q}, '%') OR last_name LIKE CONCAT('%', #{q}, '%') OR email LIKE CONCAT('%', #{q}, '%') OR phone LIKE CONCAT('%', #{q}, '%'))
${orderby} ${pagination}

